# @cctt_verify {"v":2,"sym":"sympy.polys.tests.test_polytools.test_same_root","kind":"function","src_hash":"f928eba658ff89b3","in":{"base":"Any"},"out":{"base":"Any","pred":"[i for i, r in enumerate(f.all_roots()) if eq(r, r0)] == [3]"},"spec":{"lhs":"test_same_root()","rhs":"test_same_root produces the expected output","over":{"base":"Any"},"name":"test_same_root_correct"},"guarantee":"test_same_root produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.polys.tests.test_polytools.test_same_root_correct","statement":"Path(test_same_root(x), test_same_root produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"bb6a4c4c445716fe"}
def test_same_root():
    f = Poly(x**4 + x**3 + x**2 + x + 1)
    eq = f.same_root
    r0 = exp(2 * I * pi / 5)
    assert [i for i, r in enumerate(f.all_roots()) if eq(r, r0)] == [3]

    raises(PolynomialError,
           lambda: Poly(x + 1, domain=QQ).same_root(0, 0))
    raises(DomainError,
           lambda: Poly(x**2 + 1, domain=FF(7)).same_root(0, 0))
    raises(DomainError,
           lambda: Poly(x ** 2 + 1, domain=ZZ_I).same_root(0, 0))
    raises(DomainError,
           lambda: Poly(y * x**2 + 1, domain=ZZ[y]).same_root(0, 0))
    raises(MultivariatePolynomialError,
           lambda: Poly(x * y + 1, domain=ZZ).same_root(0, 0))


